  const existingFulfillment = (await fileExists(fulfillmentJsonPath))
    ? JSON.parse(await readFile(fulfillmentJsonPath, 'utf8'))
    : null;
  const fulfillment = mergeRequestFulfillment(
    buildRequestFulfillmentModel(task, featureId),
    existingFulfillment,
  );
